def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.dml.color import RGBColor
    import os
    import numpy as np

    # Utility function to get the RGB tuple from a color object
    def get_rgb_tuple(color):
        if hasattr(color, 'rgb') and color.rgb is not None:
            return tuple(color.rgb)
        return None

    # Known RGB values for 'light blue' (could be expanded for tolerance)
    LIGHT_BLUE_RGBS = [
        (173, 216, 230),  # lightblue (web)
        (191, 239, 255),  # pptx theme variant
        (0, 176, 240),    # pptx 'light blue' accent
        (180, 210, 255),  # another plausible variant
    ]
    COLOR_TOLERANCE = 20  # Accept color within this Euclidean RGB distance

    # Helper: check if rgb matches any known light blue
    def is_light_blue(rgb):
        if rgb is None:
            return False
        for ref_rgb in LIGHT_BLUE_RGBS:
            if np.linalg.norm(np.array(rgb) - np.array(ref_rgb)) <= COLOR_TOLERANCE:
                return True
        return False

    # Load the modified presentation
    if not os.path.exists(modified_ppt_path):
        return ("Modified PPT not found.", 0.0)
    prs = Presentation(modified_ppt_path)
    slide = None
    for s in prs.slides:
        if hasattr(s, 'slide_number') and s.slide_number == 4:
            slide = s
            break
    if slide is None:
        # Fallback: 0-based index
        if len(prs.slides) >= 4:
            slide = prs.slides[3]
        else:
            return ("Slide 4 does not exist in the modified presentation.", 0.0)
    # Check background color
    bg = slide.background
    fill = bg.fill
    if not fill or fill.type is None:
        return ("Slide 4 background has no fill.", 0.0)

    rgb = None
    if fill.type == 1:  # solid
        rgb = get_rgb_tuple(fill.fore_color)
    elif fill.type == 3:  # pattern
        rgb = get_rgb_tuple(fill.fore_color)
    # else: could be gradient/picture/other, not a solid color
    if rgb is None:
        return ("Slide 4 background color cannot be determined; not a solid (RGB) color.", 0.0)
    if is_light_blue(rgb):
        return (f"Slide 4 background color is light blue (RGB: {rgb}).", 1.0)
    else:
        return (f"Slide 4 background color is not light blue (RGB: {rgb}).", 0.0)

