    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    num_slides = min(len(orig.slides), len(mod.slides))
    undesired_changes = []
    for i in range(num_slides):
        if i == 3:  # Slide 4 (0-based)
            continue
        o_bg = orig.slides[i].background
        m_bg = mod.slides[i].background
        o_fill = o_bg.fill
        m_fill = m_bg.fill
        # Compare fill types and RGB values (if solid)
        if o_fill.type != m_fill.type:
            undesired_changes.append(i+1)
            continue
        if o_fill.type == 1 and m_fill.type == 1:
            o_rgb = getattr(o_fill.fore_color, 'rgb', None)
            m_rgb = getattr(m_fill.fore_color, 'rgb', None)
            if o_rgb != m_rgb:
                undesired_changes.append(i+1)
    if undesired_changes:
        return (f"Backgrounds of slides {undesired_changes} were changed.", 0.0)
    return ("No undesired background changes detected on other slides.", 1.0)

