    mod = Presentation(modified_ppt_path)
    num_slides = min(len(orig.slides), len(mod.slides))
    # Only allow background color change on slide 4
    for i in range(num_slides):
        if i == 3:  # Slide 4 is allowed to change background
            # Check other content: text, shapes, images
            o_slide = orig.slides[i]
            m_slide = mod.slides[i]
            # Compare shapes count
            if len(o_slide.shapes) != len(m_slide.shapes):
                return ("Shapes were added or removed on Slide 4.", 0.0)
            # Compare text in shapes
            for o_shape, m_shape in zip(o_slide.shapes, m_slide.shapes):
                if hasattr(o_shape, 'text') and hasattr(m_shape, 'text'):
                    if o_shape.text != m_shape.text:
                        return ("Text was changed on Slide 4 (besides background).", 0.0)
            # Could add more types as needed
            continue
        # All other slides: content must be identical
        o_slide = orig.slides[i]
        m_slide = mod.slides[i]
        if len(o_slide.shapes) != len(m_slide.shapes):
            return (f"Shapes changed on slide {i+1}.", 0.0)
        for o_shape, m_shape in zip(o_slide.shapes, m_slide.shapes):
            if hasattr(o_shape, 'text') and hasattr(m_shape, 'text'):
                if o_shape.text != m_shape.text:
                    return (f"Text changed on slide {i+1}.", 0.0)
    return ("No content changes on any slide except background color on Slide 4.", 1.0)

